from dataclasses import dataclass
from enum import Enum

class DataRegion(Enum):
    EU = "eu"; US = "us"; CN = "cn"; APAC = "apac"; GLOBAL = "global"

class TransferGateResult(Enum):
    PERMIT           = "permit"
    PERMIT_WITH_MEASURES = "permit_with_measures"
    DENY             = "deny"

@dataclass
class TransferGateDecision:
    result: TransferGateResult
    mechanism: str        # adequacy / DPF / SCC / pseudonymised / denied
    measures: list[str]   # required supplementary measures
    reason: str

# Registry of approved transfer routes: (source_region, target_region) → mechanism
APPROVED_ROUTES: dict[tuple[str, str], str] = {
    ("eu", "eu"):   "same-region",
    ("eu", "us"):   "DPF+SCC",     # DPF-certified provider + SCCs as backup
    ("eu", "apac"): "SCC",
    ("us", "us"):   "same-region",
    ("cn", "cn"):   "same-region",
}

TIA_REGISTRY: dict[str, "TransferImpactAssessment"] = {}  # tia_id → TIA

def evaluate_transfer_gate(
    source_region: DataRegion,
    target_region: DataRegion,
    label,               # SensitivityLevel
    pseudonymised: bool = False,
) -> TransferGateDecision:
    src, tgt = source_region.value, target_region.value

    if src == tgt:
        return TransferGateDecision(
            TransferGateResult.PERMIT, "same-region", [], "Same-region transfer always permitted"
        )

    # China: block all cross-border by default
    if src == "cn" or tgt == "cn":
        return TransferGateDecision(
            TransferGateResult.DENY, "denied", [],
            "China (PIPL) cross-border transfer requires CAC security assessment — use CN-resident endpoint"
        )

    mechanism = APPROVED_ROUTES.get((src, tgt))
    if mechanism is None:
        if pseudonymised:
            return TransferGateDecision(
                TransferGateResult.PERMIT_WITH_MEASURES,
                "pseudonymised",
                ["Verify pseudonymisation key never leaves source region",
                 "Validate token coverage before transfer"],
                "No approved route; pseudonymisation applied — permitted with measures"
            )
        return TransferGateDecision(
            TransferGateResult.DENY, "denied", [],
            f"No approved transfer route from {src} to {tgt}"
        )

    # Check active TIA exists for high-risk routes
    if mechanism in ("DPF+SCC", "SCC"):
        active_tias = [t for t in TIA_REGISTRY.values()
                       if t.is_transfer_permitted() and t.vendor_country.lower() == tgt]
        if not active_tias:
            return TransferGateDecision(
                TransferGateResult.DENY, "denied", [],
                f"Transfer route {mechanism} requires active TIA for {tgt} — none found"
            )
        measures = []
        for t in active_tias:
            measures.extend(t.measures_required())
        return TransferGateDecision(
            TransferGateResult.PERMIT_WITH_MEASURES, mechanism,
            list(set(measures)), f"Transfer permitted via {mechanism} with TIA measures"
        )

    return TransferGateDecision(
        TransferGateResult.PERMIT, mechanism, [], f"Transfer permitted via {mechanism}"
    )
